const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const filters = body.filters || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
// Accept client_id from body.filters.client_id (clxApi.adminGet wraps args in filters,
// matching every other admin webhook's convention) OR from body.client_id
// (direct callers / curl tests). filters wins if both present.
const client_id = String(filters.client_id || body.client_id || '').trim();
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
if (!client_id) return { json: { ok: false, status: 400, error: 'client_id required' } };
return { json: { token, client_id } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true, client_id: $('Extract Inputs').item.json.client_id } };

// DIAGNOSTIC BUILD — captures debug info under response.debug so we can
// see exactly which upstream-access pattern works on this n8n version.
// Revert this to the plain allOf() version once Mary confirms the right
// accessor for n8n 2.10.2 parallel-branch convergence.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const probe = function (name) {
  const out = { node: name };
  try { out.allLen = $(name).all().length; } catch (e) { out.allErr = String(e && e.message || e).slice(0, 120); }
  try { out.firstJson = JSON.stringify($(name).first().json).slice(0, 200); } catch (e) { out.firstErr = String(e && e.message || e).slice(0, 120); }
  try {
    if (typeof $items === 'function') {
      out.itemsLen = $items(name).length;
      try { out.itemsFirst = JSON.stringify($items(name)[0] && $items(name)[0].json).slice(0, 200); } catch (e2) {}
    } else { out.itemsAvail = false; }
  } catch (e) { out.itemsErr = String(e && e.message || e).slice(0, 120); }
  try { out.lastJson = JSON.stringify($(name).last().json).slice(0, 100); } catch (e) {}
  return out;
};
const clientArr = allOf('Query Client');
const client = clientArr[0] || null;
const statsArr = allOf('Query Lead Stats');
const recentArr = allOf('Query Recent Leads');
const debug = {
  inputItemsLen: (function () { try { return $input.all().length; } catch (e) { return 'err: ' + e.message; } })(),
  allOfClient: clientArr.length,
  allOfStats: statsArr.length,
  allOfRecent: recentArr.length,
  queryClient: probe('Query Client'),
  queryLeadStats: probe('Query Lead Stats'),
  queryRecentLeads: probe('Query Recent Leads')
};
if (!client) return { json: { ok: true, client: null, debug: debug } };
const monthStart = new Date(); monthStart.setDate(1); monthStart.setHours(0,0,0,0);
const monthStartTs = monthStart.getTime();
let contacted = 0, replied = 0, booked_mtd = 0;
statsArr.forEach(function (r) {
  const s = r.lead_status || '';
  if (s !== 'New Lead' && s !== 'New' && s !== '') contacted += 1;
  if (r.reply_detected === true) replied += 1;
  if (r.meeting_scheduled === true && r.date_created && new Date(r.date_created).getTime() >= monthStartTs) booked_mtd += 1;
});
const stats = {
  total_leads: statsArr.length,
  contacted: contacted,
  replied: replied,
  booked_mtd: booked_mtd
};
return { json: { ok: true, client: client, stats: stats, recent_leads: recentArr, debug: debug } };
